#!/bin/bash
# GENERATED by mcp-benchmark/scripts/sync_ec2_repos.py -- do not hand-edit.
set -euo pipefail

# corepack downloads the repo-pinned pnpm (some servers pin a version via
# package.json "packageManager") without the interactive Y/n prompt that would
# otherwise hang a non-interactive / sudo build.
export COREPACK_ENABLE_DOWNLOAD_PROMPT=0
# pnpm 10/11 treats a dependency build script it won't auto-run (e.g. esbuild) as a
# hard ERR_PNPM_IGNORED_BUILDS failure, and re-checks deps before `pnpm exec`/`run`,
# which re-triggers it. We only need a tsc compile (esbuild ships prebuilt binaries),
# so opt out in the user ~/.npmrc that pnpm actually reads (npm_config_* env vars and
# project .npmrc are NOT honored for these pnpm-specific keys under corepack here).
_NPMRC="${HOME:-/root}/.npmrc"
grep -qs '^strict-dep-builds=' "$_NPMRC" || echo 'strict-dep-builds=false' >> "$_NPMRC"
grep -qs '^verify-deps-before-run=' "$_NPMRC" || echo 'verify-deps-before-run=false' >> "$_NPMRC"

REPO_ROOT="$(cd "$(dirname "$0")/.." && pwd)"
SERVERS_DIR="${REPO_ROOT}/servers"
ADAPTERS_DIR="${REPO_ROOT}/ec2/adapters"
mkdir -p "${SERVERS_DIR}"
cd "${SERVERS_DIR}"

checkout_pinned_commit() {
  local name="$1"; local commit="$2"
  [ -z "$commit" ] && return
  git -C "$name" rev-parse --is-inside-work-tree >/dev/null 2>&1 || return 0
  local current; current="$(git -C "$name" rev-parse HEAD)"
  [ "$current" = "$commit" ] && return 0
  # Force checkout to the pinned commit. These are machine-managed vendor clones;
  # any working-tree diff is regenerable build/lockfile churn (e.g. npm rewriting
  # package-lock.json), never hand edits. -f discards tracked changes but preserves
  # untracked files, so the vendored stdio-adapter.mjs survives.
  echo "INFO: checkout pinned $name ($commit)"
  git -C "$name" fetch --tags --force origin "$commit" >/dev/null 2>&1 || git -C "$name" fetch --tags --force origin
  git -C "$name" checkout -f --detach "$commit"
}

is_git_checkout() { git -C "$1" rev-parse --is-inside-work-tree >/dev/null 2>&1; }

sync_adapter() {
  local name="$1"
  local source_path="${ADAPTERS_DIR}/${name}/stdio-adapter.mjs"
  [ -f "${source_path}" ] || return 0
  cp "${source_path}" "${SERVERS_DIR}/${name}/stdio-adapter.mjs"
  chmod +x "${SERVERS_DIR}/${name}/stdio-adapter.mjs" 2>/dev/null || true
  echo "INFO: synced adapter for ${name}"
}

clone_repo() {
  local name="$1"; local url="$2"; local commit="${3:-}"
  if [ -d "${name}" ] && ! is_git_checkout "${name}"; then
    if [ -z "$(find "${name}" -mindepth 1 -maxdepth 1 -print -quit 2>/dev/null)" ]; then rmdir "${name}"; fi
  fi
  if is_git_checkout "${name}"; then checkout_pinned_commit "${name}" "${commit}"; sync_adapter "${name}"; return; fi
  if [ -d "${name}" ]; then echo "INFO: using existing dir ${name}"; sync_adapter "${name}"; return; fi
  echo "INFO: cloning ${name} from ${url}"
  git clone "${url}" "${name}"
  checkout_pinned_commit "${name}" "${commit}"
  sync_adapter "${name}"
}

has_script() { node -e "const p=require('./package.json');process.exit(p.scripts&&p.scripts['$1']?0:1)"; }

build_repo() {
  local name="$1"
  [ -f "${name}/package.json" ] || { echo "INFO: no package.json for ${name}; skipping build"; return 0; }
  # A build failure for ONE server must not abort the whole tier (mirrors install-poc.sh):
  # run in a subshell with `set +e`, guard every step, and always `return 0`.
  (
    set +e
    cd "${name}" || exit 0
    if [ -f pnpm-workspace.yaml ]; then
      # pnpm 10/11 aborts (ERR_PNPM_IGNORED_BUILDS) when a dependency build script
      # (esbuild) isn't approved, and re-checks deps before exec/run -- re-triggering
      # it. Approve esbuild via the workspace allow-list so the install exits 0.
      # Appended only if absent; the force-checkout reverts pnpm-workspace.yaml each run.
      grep -q 'onlyBuiltDependencies' pnpm-workspace.yaml || printf '\nonlyBuiltDependencies:\n  - esbuild\n' >> pnpm-workspace.yaml
      npx pnpm install || echo "WARN: pnpm install issues for ${name}; continuing"
      if [ "${name}" = "context7" ]; then
        # @upstash/context7-mcp lives in packages/mcp and builds to packages/mcp/dist,
        # but the route command runs servers/context7/dist/index.js -- expose via symlink.
        npx pnpm --filter @upstash/context7-mcp exec tsc \
          || ./node_modules/.bin/tsc -p packages/mcp/tsconfig.json \
          || echo "WARN: context7 tsc failed"
        chmod 755 packages/mcp/dist/index.js 2>/dev/null || true
        ln -sfn packages/mcp/dist dist
      elif has_script "build:stdio"; then npx pnpm run build:stdio || echo "WARN: build:stdio failed for ${name}"
      elif has_script "build"; then npx pnpm run build || echo "WARN: build failed for ${name}"
      else echo "INFO: pnpm workspace ${name}, no build script"; fi
    elif [ "${name}" = "metmuseum-mcp" ]; then
      # `prebuild` runs `pnpm run lint:check`, which pulls a bun binary and hangs --
      # skip all lifecycle scripts and compile straight to dist/.
      npm install --ignore-scripts || echo "WARN: npm install failed for ${name}"
      npx tsc || echo "WARN: tsc failed for ${name}"
    else
      npm install || echo "WARN: npm install failed for ${name}"
      if has_script "build:stdio"; then npm run build:stdio || echo "WARN: build:stdio failed for ${name}"
      elif has_script "build"; then npm run build || echo "WARN: build failed for ${name}"
      else echo "INFO: no build script for ${name}; using checked-in entrypoints"; fi
    fi
  )
  return 0
}


# npm-package servers (bun-built upstream) -> shared servers/_cand_npm
mkdir -p _cand_npm
( cd _cand_npm && [ -f package.json ] || npm init -y >/dev/null 2>&1 )
( cd _cand_npm && npm install --no-audit --no-fund @johnpapa/mcp-starwars@1.0.1 )
( cd _cand_npm && npm install --no-audit --no-fund @sylphx/pdf-reader-mcp )
( cd _cand_npm && npm install --no-audit --no-fund mcp-ip-geolocator@1.0.0 )
mkdir -p "mcp-starwars" && sync_adapter "mcp-starwars"
mkdir -p "ip-geolocation-mcp" && sync_adapter "ip-geolocation-mcp"

# clone + checkout pinned commit (+ sync vendored adapter)
clone_repo "mcp-dnd-5e" "https://github.com/carromeu/mcp-dnd-5e" "506dfd904d0fcfe60569b5bfff295e98823c2cb3"
clone_repo "context7" "https://github.com/upstash/context7" "5d7e893a5adf30f91183763ae8e65e9eaf8dd17e"
clone_repo "open-meteo-mcp-server" "https://github.com/cmer81/open-meteo-mcp" "d1f0c7b9434d4253a7b40c83325c011d37b23a2d"
clone_repo "whois-mcp" "https://github.com/bharathvaj-ganesan/whois-mcp" "da2023f1910bfcb98bd702a8e851860608a04a9c"
clone_repo "json-query-mcp" "https://github.com/mgraczyk/json-query-mcp" "c3e58e723511b787daae475d9ad1a19774f6978b"
clone_repo "calculator-mcp" "https://github.com/wrtnlabs/calculator-mcp" "b59604170c581a4fae6353078f726aca0c1e0373"
clone_repo "paper-search-mcp" "https://github.com/openags/paper-search-mcp" "4860916c8da4e58b9cded756e0bc2327d334146d"

# Ensure pnpm is on PATH for servers whose build lifecycle scripts call pnpm
# directly. Prefer corepack (bundled with node): it installs the shim into
# node's own bin dir, which is on sudo's secure_path. A plain 'npm i -g pnpm'
# can land in /usr/local/bin and be invisible to scripts run under sudo.
if ! command -v pnpm >/dev/null 2>&1; then
  corepack enable >/dev/null 2>&1 && corepack prepare pnpm@latest --activate >/dev/null 2>&1 || npm install -g pnpm
fi

# install node deps + build where a build script exists
build_repo "mcp-dnd-5e"
build_repo "context7"
build_repo "open-meteo-mcp-server"
build_repo "whois-mcp"
build_repo "json-query-mcp"
build_repo "calculator-mcp"
build_repo "paper-search-mcp"

if [ -d "json-query-mcp" ] && [ ! -f "json-query-mcp/big.json" ]; then
  echo "INFO: generating json-query-mcp/big.json fixture"
  node -e "const fs=require('fs');const a=[];for(let i=0;i<120000;i++){a.push({id:i,name:'item_'+i,value:Math.floor(Math.cos(i)*1e6),tags:['t'+(i%50),'g'+(i%7)],desc:'lorem ipsum dolor sit amet consectetur '+i});}fs.writeFileSync('json-query-mcp/big.json',JSON.stringify(a));" || echo "WARN: failed to generate json-query big.json"
fi

echo "INFO: heavy server install complete"
